import os
import zipfile
import urllib.request
import shutil
import unreal

class MLSLabsLibTorchInstaller:
    def __init__(self):
        plugin_name = "MLSLabsRenderer"
        proj_plugin_path = os.path.join(unreal.Paths.project_plugins_dir(), plugin_name)
        eng_plugin_path = os.path.join(unreal.Paths.engine_plugins_dir(), "Marketplace", plugin_name)
        base_dir = proj_plugin_path if os.path.exists(proj_plugin_path) else eng_plugin_path
        
        # 目标路径调整为 Source/ThirdParty (Zip内部通常自带 libtorch 文件夹)
        self.destination_path = os.path.normpath(os.path.join(base_dir, "Source", "ThirdParty"))
        self.libtorch_url = "https://download.pytorch.org/libtorch/cu128/libtorch-win-shared-with-deps-2.7.0%2Bcu128.zip"
        self.temp_zip = os.path.normpath(os.path.join(unreal.Paths.project_saved_dir(), "libtorch_tmp.zip"))

    def log(self, msg):
        unreal.log(f"### [MLSLabs Setup]: {msg}")

    def run_install(self):
        parent_dir = os.path.dirname(self.destination_path)
        if not os.access(parent_dir, os.W_OK):
            unreal.EditorDialog.show_message("Permission Error", "Please run Unreal as Administrator.", unreal.AppMsgType.OK)
            return

        # 总任务量设为 100
        with unreal.ScopedSlowTask(100.0, "Installing LibTorch (This may take a while)...") as slow_task:
            slow_task.make_dialog(can_cancel=True)
            
            try:
                # 1. 下载阶段 (分配 70% 进度)
                should_download = True
                if os.path.exists(self.temp_zip):
                    if os.path.getsize(self.temp_zip) > 1000 * 1024 * 1024:
                        self.log("Local ZIP found. Skipping download.")
                        should_download = False
                        slow_task.enter_progress_frame(70.0, "ZIP already exists, skipping download...")

                if should_download:
                    self.log("Downloading LibTorch...")
                    def download_report(block_num, block_size, total_size):
                        if slow_task.should_cancel():
                            raise Exception("Download cancelled by user")
                        
                        percent = (block_num * block_size * 100) / total_size
                        # 将总下载的 100% 映射到进度条的 70%
                        current_frame_progress = min(percent * 0.7, 70.0)
                        msg = f"Downloading LibTorch: {percent:.1f}% ({int(block_num * block_size / 1024 / 1024)}MB / {int(total_size / 1024 / 1024)}MB)"
                        # enter_progress_frame 是增量式的，所以我们计算差值
                        # 但为了简单，这里直接更新对话框文本，或者使用精准计算
                        slow_task.enter_progress_frame(0, msg) 

                    req_headers = {'User-Agent': 'Mozilla/5.0'}
                    opener = urllib.request.build_opener()
                    opener.addheaders = [('User-Agent', 'Mozilla/5.0')]
                    urllib.request.install_opener(opener)
                    
                    # 使用 urlretrieve 因为它自带 reporthook
                    urllib.request.urlretrieve(self.libtorch_url, self.temp_zip, reporthook=download_report)

                # 2. 解压阶段 (分配 30% 进度)
                if slow_task.should_cancel(): return
                
                self.log("Extracting...")
                self.extract_with_progress(self.temp_zip, self.destination_path, slow_task)

                # 解压成功后可以选择删除压缩包（节省 1.2GB 空间）或保留（方便下次修复）
                if os.path.exists(self.temp_zip): os.remove(self.temp_zip)
                
                # --- 重启逻辑开始 ---
                confirm_msg = "Installation Complete! \n\nTo load the new libraries, the Editor must restart. Click OK to save all and restart, or Cancel to restart later manually."
                result = unreal.EditorDialog.show_message("Installation Finished", confirm_msg, unreal.AppMsgType.OK_CANCEL)
                
                unreal.log(f"Dialog result: {result}")
                
                if "OK" in str(result):
                    self.log("Starting reliable restart sequence...")
                    
                    # 1. 先保存所有修改，防止丢进度
                    unreal.EditorLoadingAndSavingUtils.save_dirty_packages(True, False)
                    
                    # 2. 我们尝试调用引擎最原始的重启入口
                    try:
                        # 尝试通过 Python 执行控制台命令，并指定具体的上下文
                        # 使用 unreal.get_editor_subsystem 来确保我们能触达编辑器核心
                        unreal.SystemLibrary.execute_console_command(unreal.EditorLevelLibrary.get_editor_world(), "RestartEditor")
                        
                        # 如果上面的命令还是没反应，强制退出（用户点击了OK，说明他同意重启）
                        # 如果无法自动重启，最好弹窗提示用户“请手动重启编辑器”。
                        unreal.EditorDialog.show_message("Action Required", "Auto-restart failed. Please close and reopen Unreal Editor manually to load LibTorch.", unreal.AppMsgType.OK)
                    except Exception as fallback_e:
                        self.log(f"Command failed: {fallback_e}")
                        unreal.EditorDialog.show_message("Action Required", "Auto-restart failed. Please close and reopen Unreal Editor manually to load LibTorch.", unreal.AppMsgType.OK)
                else:
                    self.log("User opted to restart later.")
                
            except Exception as e:
                self.log(f"Error: {str(e)}")
                if not slow_task.should_cancel():
                    unreal.EditorDialog.show_message("Error", f"Failed: {str(e)}", unreal.AppMsgType.OK)

    def extract_with_progress(self, zip_path, target_dir, slow_task):
        abs_target = os.path.abspath(target_dir)
        long_target = '\\\\?\\' + abs_target if os.name == 'nt' and not abs_target.startswith('\\\\?\\') else abs_target

        libtorch_path = os.path.join(long_target, "libtorch")
        if os.path.exists(libtorch_path):
            shutil.rmtree(libtorch_path)

        with zipfile.ZipFile(zip_path, 'r') as zip_ref:
            members = zip_ref.infolist()
            total_files = len(members)
            
            for i, item in enumerate(members):
                if slow_task.should_cancel():
                    raise Exception("Extraction cancelled by user")

                # 每解压一部分文件更新一次进度条 (映射到最后的 30%)
                if i % 10 == 0:
                    progress_increment = (1.0 / total_files) * 30.0 * 10
                    slow_task.enter_progress_frame(progress_increment, f"Extracting: {item.filename[:50]}...")

                normalized_item_path = item.filename.replace('/', os.sep)
                target_file_path = os.path.join(long_target, normalized_item_path)
                
                if item.is_dir():
                    os.makedirs(target_file_path, exist_ok=True)
                else:
                    os.makedirs(os.path.dirname(target_file_path), exist_ok=True)
                    with zip_ref.open(item) as source, open(target_file_path, 'wb') as target:
                        shutil.copyfileobj(source, target)

def install_pytorch_unified():
    installer = MLSLabsLibTorchInstaller()
    installer.run_install()

if __name__ == "__main__":
    install_pytorch_unified()